-- Delta import: 126 codici nuovi + 3 descrizioni aggiornate.
-- Sorgente: codici_descrizioni_catalogo_finale.xlsx

-- 1. Nuovi prodotti
ON CONFLICT (codice) DO UPDATE SET
  descrizione = EXCLUDED.descrizione,
  famiglia    = COALESCE(products.famiglia, EXCLUDED.famiglia),
  updated_at  = now();

-- 2. Aggiorna descrizioni mancanti / cambiate
UPDATE products SET descrizione = 'MORSETTO UNIVERSALE Ø6MM', nome = COALESCE(NULLIF(nome, ''), 'MORSETTO UNIVERSALE Ø6MM'), updated_at = now() WHERE codice = '5000614';
UPDATE products SET descrizione = 'MORSETTO MULTIPLO GRANDE ER ST', nome = COALESCE(NULLIF(nome, ''), 'MORSETTO MULTIPLO GRANDE ER ST'), updated_at = now() WHERE codice = '5006504L';
UPDATE products SET descrizione = 'MORSETTO CLICKIT ELBOW ST', nome = COALESCE(NULLIF(nome, ''), 'MORSETTO CLICKIT ELBOW ST'), updated_at = now() WHERE codice = '5006539';